using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, object> AppConfig = new()
    {
        ["environment"] = "production",
        ["maxRetries"] = 3,
        ["timeoutSeconds"] = 30,
        ["featureFlags"] = new Dictionary<string, bool>
        {
            ["darkMode"] = true,
            ["betaFeatures"] = false
        }
    };

    [McpServerResource(
        UriTemplate = "config://app",
        Name = "App Configuration",
        MimeType = "application/json"),
     Description("Returns the current application configuration as JSON.")]
    public static string GetAppConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/{section}",
        Name = "Config Section",
        MimeType = "application/json"),
     Description("Returns a specific section of the application configuration.")]
    public static string GetConfigSection(
        [Description("Configuration section name (e.g., 'featureFlags')")] string section)
    {
        if (AppConfig.TryGetValue(section, out var value))
            return JsonSerializer.Serialize(value, new JsonSerializerOptions { WriteIndented = true });

        return JsonSerializer.Serialize(new { error = $"Section '{section}' not found" });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Validates a configuration key-value pair against known constraints.")]
    public static string ValidateConfig(
        [Description("The configuration key to validate")] string key,
        [Description("The value to validate")] string value)
    {
        return key.ToLowerInvariant() switch
        {
            "maxretries" when int.TryParse(value, out var n) && n is >= 1 and <= 10
                => $"✅ '{key}={value}' is valid.",
            "maxretries"
                => $"❌ '{key}' must be an integer between 1 and 10.",
            "timeoutseconds" when int.TryParse(value, out var n) && n is >= 1 and <= 300
                => $"✅ '{key}={value}' is valid.",
            "timeoutseconds"
                => $"❌ '{key}' must be an integer between 1 and 300.",
            "environment" when value is "development" or "staging" or "production"
                => $"✅ '{key}={value}' is valid.",
            "environment"
                => $"❌ '{key}' must be one of: development, staging, production.",
            _ => $"⚠️ Unknown configuration key '{key}'."
        };
    }
}

