 using System.ComponentModel;
 using ModelContextProtocol.Server;

 [McpServerToolType]
 public static class ConfigTools
 {
     [McpServerTool, Description("Validates a configuration key-value pair against known constraints.")]
     public static string ValidateConfig(
         [Description("The configuration key to validate")] string key,
         [Description("The value to validate")] string value)
     {
         return key.ToLowerInvariant() switch
         {
             "maxretries" when int.TryParse(value, out var n) && n is >= 1 and <= 10
                 => $"✅ '{key}={value}' is valid.",
             "maxretries"
                 => $"❌ '{key}' must be an integer between 1 and 10.",
             "timeoutseconds" when int.TryParse(value, out var n) && n is >= 1 and <= 300
                 => $"✅ '{key}={value}' is valid.",
             "timeoutseconds"
                 => $"❌ '{key}' must be an integer between 1 and 300.",
             "environment" when value is "development" or "staging" or "production"
                 => $"✅ '{key}={value}' is valid.",
             "environment"
                 => $"❌ '{key}' must be one of: development, staging, production.",
             _ => $"⚠️ Unknown configuration key '{key}'."
         };
     }
 }

